//! Groth16 heavy tests: golden vectors (py_ecc verified), tamper checks,
//! invariants, and stress.
//!
//! All "golden" constants were generated by scripts/gen_groth16_vectors.py
//! and cross-checked against py_ecc.bn128 pairing arithmetic.
//!
//! Setup (toxic waste, for test only):
//!   alpha_s=3, beta_s=5, gamma_s=7, delta_s=11
//!
//! Case 1: n_public=0, proof.A=15*G1, proof.B=G2, proof.C=INF
//! Case 2: n_public=1 (s=9), k0=13, k1=17, proof.A=1177*G1, proof.B=G2

const std     = @import("std");
const g1      = @import("g1.zig");
const g2      = @import("g2.zig");
const G1      = g1.G1;
const G2      = g2.G2;
const fp      = @import("fp.zig");
const groth16 = @import("groth16.zig");
const Proof      = groth16.Proof;
const VerifyingKey = groth16.VerifyingKey;

// ── Hex-decode helpers ────────────────────────────────────────────────────────

fn g1FromHex(comptime hex: *const [128:0]u8) G1 {
    var bytes: [64]u8 = undefined;
    _ = std.fmt.hexToBytes(&bytes, hex) catch unreachable;
    return G1.fromAffineBytes(&bytes);
}

fn g2FromHex(comptime hex: *const [256:0]u8) G2 {
    var bytes: [128]u8 = undefined;
    _ = std.fmt.hexToBytes(&bytes, hex) catch unreachable;
    return G2.fromAffineBytes(&bytes);
}

fn g1Inf() G1 { return G1.INFINITY; }

// ── Shared VK constants (same across Case 1 and Case 2) ──────────────────────

