// ── Case 2: n_public=1 (s=9), gamma_abc=[13*G1, 17*G1], proof.A=1177*G1 ─────

const CASE2_A    = "00e81ea8d81055564c708a31eda4cd0846a5dd383e847c41c0991fc9b00b728d24f716691c5aeeeb11a21cc308bb35583e4d15b43b84ad28d7130659d3190d9b";
const CASE2_B    = CASE1_B; // G2 generator
const CASE2_ABC0 = "05e86f8cc8a7a4f10f56093465679f17f8b8c3fdb41469e408b529e030f52f3f2857bd14bbc09767bed8e913d3ccb42b2bc8738f715417dd6f020725d22bcd90";
