// ── Golden: Case 1 (no public inputs) ────────────────────────────────────────

test "golden case1: no public inputs — must verify" {
    var abc0 = [_]G1{G1.INFINITY};   // gamma_abc[0] = INF
    const vk = VerifyingKey{
        .alpha     = g1FromHex(ALPHA),
        .beta      = g2FromHex(BETA),
        .gamma     = g2FromHex(GAMMA),
        .delta     = g2FromHex(DELTA),
        .gamma_abc = &abc0,
    };
    const proof = Proof{
        .a = g1FromHex(CASE1_A),
        .b = g2FromHex(CASE1_B),
        .c = G1.INFINITY,
    };
    try std.testing.expect(groth16.verify(vk, proof, &[_][4]u64{}));
}

// ── Golden: Case 2 (one public input s=9) ────────────────────────────────────

test "golden case2: pub_input s=9 — must verify" {
    var abc = [_]G1{ g1FromHex(CASE2_ABC0), g1FromHex(CASE2_ABC1) };
    const vk = VerifyingKey{
        .alpha     = g1FromHex(ALPHA),
        .beta      = g2FromHex(BETA),
        .gamma     = g2FromHex(GAMMA),
        .delta     = g2FromHex(DELTA),
        .gamma_abc = &abc,
    };
    const proof = Proof{
        .a = g1FromHex(CASE2_A),
        .b = g2FromHex(CASE2_B),
        .c = G1.INFINITY,
    };
    try std.testing.expect(groth16.verify(vk, proof, &[_][4]u64{PUB_S9}));
}

// ── Tamper: wrong proof.A ─────────────────────────────────────────────────────

test "tamper: wrong proof.A — must reject" {
    var abc0 = [_]G1{G1.INFINITY};
    const vk = VerifyingKey{
        .alpha     = g1FromHex(ALPHA),
        .beta      = g2FromHex(BETA),
        .gamma     = g2FromHex(GAMMA),
        .delta     = g2FromHex(DELTA),
        .gamma_abc = &abc0,
    };
    const proof = Proof{
        .a = g1FromHex(TAMPER_A),  // A+1*G1 — invalid
        .b = g2FromHex(CASE1_B),
        .c = G1.INFINITY,
    };
    try std.testing.expect(!groth16.verify(vk, proof, &[_][4]u64{}));
}

test "tamper: wrong public input (s=10 instead of 9) — must reject" {
    var abc = [_]G1{ g1FromHex(CASE2_ABC0), g1FromHex(CASE2_ABC1) };
    const vk = VerifyingKey{
        .alpha     = g1FromHex(ALPHA),
        .beta      = g2FromHex(BETA),
        .gamma     = g2FromHex(GAMMA),
        .delta     = g2FromHex(DELTA),
        .gamma_abc = &abc,
    };
    const proof = Proof{
        .a = g1FromHex(CASE2_A),
        .b = g2FromHex(CASE2_B),
        .c = G1.INFINITY,
    };
    const pub_bad: [4]u64 = .{ 10, 0, 0, 0 };  // s=10, not 9
    try std.testing.expect(!groth16.verify(vk, proof, &[_][4]u64{pub_bad}));
}

test "tamper: swap proof.A and proof.C — must reject" {
    // Case1: A=15*G1, C=INF. Swap → A=INF, C=15*G1. Product breaks.
    var abc0 = [_]G1{G1.INFINITY};
    const vk = VerifyingKey{
        .alpha     = g1FromHex(ALPHA),
        .beta      = g2FromHex(BETA),
        .gamma     = g2FromHex(GAMMA),
        .delta     = g2FromHex(DELTA),
        .gamma_abc = &abc0,
    };
    const proof = Proof{
        .a = G1.INFINITY,
        .b = g2FromHex(CASE1_B),
        .c = g1FromHex(CASE1_A),   // A and C swapped
    };
    try std.testing.expect(!groth16.verify(vk, proof, &[_][4]u64{}));
}

test "tamper: wrong VK alpha — must reject" {
    // Use alpha=G1 instead of 3*G1 — breaks e(-alpha,beta)
    var abc0 = [_]G1{G1.INFINITY};
    const vk = VerifyingKey{
        .alpha     = G1.GENERATOR,  // wrong: should be 3*G1
        .beta      = g2FromHex(BETA),
        .gamma     = g2FromHex(GAMMA),
        .delta     = g2FromHex(DELTA),
        .gamma_abc = &abc0,
    };
    const proof = Proof{
        .a = g1FromHex(CASE1_A),
        .b = g2FromHex(CASE1_B),
        .c = G1.INFINITY,
    };
    try std.testing.expect(!groth16.verify(vk, proof, &[_][4]u64{}));
}

// ── Invariants ────────────────────────────────────────────────────────────────

test "invariant: double negation negG1(negG1(P)) affine roundtrip" {
    // Can't call negG1 directly (private), but verify uses it.
    // Instead: check that G1 addJac(P, neg(P)) == INFINITY for various scalars.
    const scalars: []const [4]u64 = &.{
        .{ 1, 0, 0, 0 },
        .{ 7, 0, 0, 0 },
        .{ 15, 0, 0, 0 },
        .{ 1177, 0, 0, 0 },
        .{ 0xdeadbeef, 0, 0, 0 },
    };
    for (scalars) |s| {
        const P  = G1.GENERATOR.scalarMul(s);
        const nP = G1.GENERATOR.scalarMul(s);
        // Build neg manually: negate Y in Jacobian
        const neg_P = G1{ .x = nP.x, .y = fp.neg(nP.y), .z = nP.z };
        const sum = P.addJac(neg_P);
        try std.testing.expect(sum.isInfinity());
    }
}

test "invariant: MSM linearity — msm([P,Q],[a+b]) == msm([P,Q],[a]) + msm([P,Q],[b])" {
    // msm with gamma_abc=[G1, G1]:
    //   msm(gamma_abc, [s]) = G1 + s*G1 = (1+s)*G1
    // Linearity: msm(s1+s2) == msm(s1) + msm(s2)
    // We test via verify: if we split a scalar into two addends across two calls.
    // Here we just test the scalar homogeneity via G1.scalarMul.
    const G = G1.GENERATOR;
    const pairs: []const struct { a: u64, b: u64 } = &.{
        .{ .a = 3,  .b = 5  },
        .{ .a = 11, .b = 17 },
        .{ .a = 0,  .b = 42 },
    };
    for (pairs) |p| {
        const sa: [4]u64 = .{ p.a, 0, 0, 0 };
        const sb: [4]u64 = .{ p.b, 0, 0, 0 };
        const sab: [4]u64 = .{ p.a + p.b, 0, 0, 0 };
        const Pa  = G.scalarMul(sa);
        const Pb  = G.scalarMul(sb);
        const Pab = G.scalarMul(sab);
        const sum = Pa.addJac(Pb);
        // Compare via affine bytes
        var got: [64]u8 = undefined;
        var exp: [64]u8 = undefined;
        sum.toAffineBytes(&got);
        Pab.toAffineBytes(&exp);
        try std.testing.expectEqualSlices(u8, &exp, &got);
    }
}

test "invariant: frFromBytes(0) == .{0,0,0,0}" {
    const buf = [_]u8{0} ** 32;
    const limbs = groth16.frFromBytes(&buf);
    try std.testing.expectEqual(limbs, [4]u64{ 0, 0, 0, 0 });
}

test "invariant: frFromBytes big-endian byte order" {
    // Byte 0 is most significant → limb[3]
    var buf = [_]u8{0} ** 32;
    buf[0] = 0x01;  // bit lands in limb[3], position 63
    const limbs = groth16.frFromBytes(&buf);
    try std.testing.expectEqual(limbs[3], 0x0100000000000000);
    try std.testing.expectEqual(limbs[0], 0);
}

// ── Stress: N random-scalar invalid proofs must all fail ─────────────────────

test "stress: 32 random-scalar proofs against case2 VK all reject" {
    // VK for case2. We make proofs with random A (different scalar each time).
    // None of them satisfies the pairing equation → all must return false.
    // We use a simple LCG to generate deterministic pseudo-random scalars.
    var abc = [_]G1{ g1FromHex(CASE2_ABC0), g1FromHex(CASE2_ABC1) };
    const vk = VerifyingKey{
        .alpha     = g1FromHex(ALPHA),
        .beta      = g2FromHex(BETA),
        .gamma     = g2FromHex(GAMMA),
        .delta     = g2FromHex(DELTA),
        .gamma_abc = &abc,
    };

    // LCG: x_{n+1} = (a*x_n + c) mod 2^64
    var rng: u64 = 0xdeadbeefcafe1234;
    const lcg_a: u64 = 6364136223846793005;
    const lcg_c: u64 = 1442695040888963407;

    var rejected: usize = 0;
    var i: usize = 0;
    while (i < 32) : (i += 1) {
        rng = lcg_a *% rng +% lcg_c;
        // Skip scalars that happen to equal the valid t=1177 (astronomically unlikely but safe)
        const scalar: u64 = rng | 1;  // force odd — valid t=1177 is odd too, but fine
        if (scalar == 1177) continue;

        const A_fake = G1.GENERATOR.scalarMul(.{ scalar, 0, 0, 0 });
        const proof = Proof{
            .a = A_fake,
            .b = g2FromHex(CASE2_B),
            .c = G1.INFINITY,
        };
        if (!groth16.verify(vk, proof, &[_][4]u64{PUB_S9})) {
            rejected += 1;
        }
    }
    try std.testing.expectEqual(rejected, 32);
}

test "stress: case2 rejects all 8 single-field tampers" {
    // Systematically tamper each component of the proof one at a time.
    var abc = [_]G1{ g1FromHex(CASE2_ABC0), g1FromHex(CASE2_ABC1) };
    const vk = VerifyingKey{
        .alpha     = g1FromHex(ALPHA),
        .beta      = g2FromHex(BETA),
        .gamma     = g2FromHex(GAMMA),
        .delta     = g2FromHex(DELTA),
        .gamma_abc = &abc,
    };

    const good_A = g1FromHex(CASE2_A);
    const good_B = g2FromHex(CASE2_B);
    const other  = G1.GENERATOR;  // any non-infinity G1

    // (tampered_A, tampered_C, pub_input, should_fail)
    const cases = [_]struct { a: G1, c: G1, inp: [4]u64, fail: bool }{
        // 1. Correct → must PASS (sanity)
        .{ .a = good_A, .c = G1.INFINITY, .inp = PUB_S9,          .fail = false },
        // 2. Wrong A
        .{ .a = other,  .c = G1.INFINITY, .inp = PUB_S9,          .fail = true  },
        // 3. Non-infinity C
        .{ .a = good_A, .c = other,       .inp = PUB_S9,          .fail = true  },
        // 4. Wrong pub input (s=0)
        .{ .a = good_A, .c = G1.INFINITY, .inp = .{0,0,0,0},      .fail = true  },
        // 5. Wrong pub input (s=1)
        .{ .a = good_A, .c = G1.INFINITY, .inp = .{1,0,0,0},      .fail = true  },
        // 6. Wrong pub input (s=8)
        .{ .a = good_A, .c = G1.INFINITY, .inp = .{8,0,0,0},      .fail = true  },
        // 7. Wrong pub input (s=10)
        .{ .a = good_A, .c = G1.INFINITY, .inp = .{10,0,0,0},     .fail = true  },
        // 8. A=INFINITY (degenerate)
        .{ .a = G1.INFINITY, .c = G1.INFINITY, .inp = PUB_S9,     .fail = true  },
    };

    for (cases, 0..) |tc, idx| {
        const proof = Proof{ .a = tc.a, .b = good_B, .c = tc.c };
        const result = groth16.verify(vk, proof, &[_][4]u64{tc.inp});
        if (tc.fail) {
            if (result) {
                std.debug.print("case {} should have failed but passed\n", .{idx});
            }
            try std.testing.expect(!result);
        } else {
            try std.testing.expect(result);
        }
    }
}
